"use client";

import { useState } from "react";
import { useApp } from "@/contexts/app-context";
import { simulateRiskBucket } from "@/lib/engine/risk-engine";
import { generateRebalancingPlans } from "@/lib/engine/rebalancer";
import type { RiskEvent, RiskBucketType } from "@/lib/types";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Slider } from "@/components/ui/slider";
import { Badge } from "@/components/ui/badge";
import { DepletionChart } from "./depletion-chart";
import {
  Briefcase,
  HeartPulse,
  TrendingDown,
  ArrowDownRight,
  Plus,
  Trash2,
  Zap,
  AlertTriangle,
} from "lucide-react";

const RISK_BUCKETS: { type: RiskBucketType; name: string; icon: typeof Briefcase; description: string; color: string }[] = [
  {
    type: "income_shock",
    name: "Job Loss / Income Shock",
    icon: Briefcase,
    description: "Loss or reduction of income (job loss, disability, reduced hours)",
    color: "bg-red-50 border-red-200 text-red-700",
  },
  {
    type: "expense_shock",
    name: "Medical / Expense Shock",
    icon: HeartPulse,
    description: "Unexpected lump sum expense (medical bills, emergency repairs)",
    color: "bg-orange-50 border-orange-200 text-orange-700",
  },
  {
    type: "market_shock",
    name: "Market Crash",
    icon: TrendingDown,
    description: "Significant drop in portfolio value",
    color: "bg-purple-50 border-purple-200 text-purple-700",
  },
  {
    type: "structural_drift",
    name: "Lifestyle Inflation",
    icon: ArrowDownRight,
    description: "Gradual increase in expenses eroding savings",
    color: "bg-yellow-50 border-yellow-200 text-yellow-700",
  },
];

export function RiskEventPanel() {
  const { state, dispatch } = useApp();
  const [selectedBucket, setSelectedBucket] = useState<RiskBucketType | null>(null);
  const [severity, setSeverity] = useState(100);
  const [duration, setDuration] = useState(6);
  const [lumpSum, setLumpSum] = useState(0);

  if (!state.profile) return null;

  const addEvent = () => {
    if (!selectedBucket) return;
    const bucket = RISK_BUCKETS.find(b => b.type === selectedBucket)!;
    const event: RiskEvent = {
      id: crypto.randomUUID(),
      type: selectedBucket,
      name: bucket.name,
      severity,
      duration,
      lumpSum: selectedBucket === "expense_shock" ? lumpSum : undefined,
      isActive: true,
    };
    dispatch({ type: "ADD_RISK_EVENT", event });
    setSelectedBucket(null);
    setSeverity(100);
    setDuration(6);
    setLumpSum(0);
  };

  const runSimulation = () => {
    if (state.riskEvents.length === 0 || !state.profile) return;
    const stress = simulateRiskBucket(state.profile, { events: state.riskEvents });
    dispatch({ type: "SET_STRESS_RESULT", result: stress });
    const plans = generateRebalancingPlans(state.profile, stress);
    dispatch({ type: "SET_REBALANCING_PLANS", plans });
  };

  return (
    <div className="space-y-6">
      {/* Risk Bucket Cards */}
      <div className="grid md:grid-cols-2 gap-3">
        {RISK_BUCKETS.map(bucket => {
          const isActive = state.riskEvents.some(e => e.type === bucket.type);
          return (
            <Card
              key={bucket.type}
              className={`cursor-pointer transition-all hover:shadow-md ${
                selectedBucket === bucket.type ? "ring-2 ring-primary" : ""
              } ${isActive ? "opacity-50" : ""} border-0 shadow-sm`}
              onClick={() => !isActive && setSelectedBucket(bucket.type)}
            >
              <CardContent className="p-4 flex items-start gap-3">
                <div className={`w-10 h-10 rounded-lg flex items-center justify-center shrink-0 ${bucket.color}`}>
                  <bucket.icon className="w-5 h-5" />
                </div>
                <div>
                  <div className="font-semibold text-sm">{bucket.name}</div>
                  <div className="text-xs text-muted-foreground">{bucket.description}</div>
                  {isActive && <Badge className="mt-1 text-xs" variant="secondary">Added</Badge>}
                </div>
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* Configuration Panel */}
      {selectedBucket && (
        <Card className="border-0 shadow-sm">
          <CardHeader>
            <CardTitle className="text-sm">Configure Risk Event</CardTitle>
            <CardDescription>Set the severity and duration for this risk scenario</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <div className="flex justify-between">
                <Label>Severity</Label>
                <span className="text-sm font-semibold">{severity}%</span>
              </div>
              <Slider
                value={[severity]}
                onValueChange={([v]) => setSeverity(v)}
                max={100}
                min={10}
                step={10}
              />
              <p className="text-xs text-muted-foreground">
                {selectedBucket === "income_shock" && `${severity}% of income lost`}
                {selectedBucket === "expense_shock" && `Severity of the expense shock`}
                {selectedBucket === "market_shock" && `${severity}% portfolio drawdown`}
                {selectedBucket === "structural_drift" && `${severity}% monthly expense increase`}
              </p>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between">
                <Label>Duration</Label>
                <span className="text-sm font-semibold">{duration} months</span>
              </div>
              <Slider
                value={[duration]}
                onValueChange={([v]) => setDuration(v)}
                max={24}
                min={1}
                step={1}
              />
            </div>

            {selectedBucket === "expense_shock" && (
              <div>
                <Label>Lump Sum Amount ($)</Label>
                <Input
                  type="number"
                  value={lumpSum || ""}
                  onChange={e => setLumpSum(parseFloat(e.target.value) || 0)}
                  placeholder="e.g., 15000"
                />
              </div>
            )}

            <Button onClick={addEvent} className="w-full">
              <Plus className="w-4 h-4 mr-2" />
              Add Risk Event
            </Button>
          </CardContent>
        </Card>
      )}

      {/* Active Events */}
      {state.riskEvents.length > 0 && (
        <Card className="border-0 shadow-sm">
          <CardHeader>
            <CardTitle className="text-sm flex items-center gap-2">
              <AlertTriangle className="w-4 h-4 text-orange-500" />
              Active Risk Events ({state.riskEvents.length})
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-2">
            {state.riskEvents.map(event => (
              <div key={event.id} className="flex items-center justify-between bg-muted/50 rounded-lg px-3 py-2">
                <div>
                  <span className="font-medium text-sm">{event.name}</span>
                  <span className="text-xs text-muted-foreground ml-2">
                    {event.severity}% severity, {event.duration} months
                    {event.lumpSum ? `, $${event.lumpSum.toLocaleString()} lump sum` : ""}
                  </span>
                </div>
                <Button
                  size="sm"
                  variant="ghost"
                  onClick={() => dispatch({ type: "REMOVE_RISK_EVENT", eventId: event.id })}
                >
                  <Trash2 className="w-3 h-3" />
                </Button>
              </div>
            ))}
            <div className="flex gap-2 pt-2">
              <Button onClick={runSimulation} className="flex-1">
                <Zap className="w-4 h-4 mr-2" />
                Run Stress Simulation
              </Button>
              <Button variant="outline" onClick={() => dispatch({ type: "CLEAR_RISK_EVENTS" })}>
                Clear All
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Stress Results */}
      {state.stressResult && (
        <div className="space-y-4">
          <Card className="border-0 shadow-sm border-l-4 border-l-red-500">
            <CardHeader>
              <CardTitle className="text-sm">Stress Test Results</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div>
                  <div className="text-xs text-muted-foreground">Adjusted Burn Rate</div>
                  <div className="text-lg font-bold">${state.stressResult.adjustedMonthlyBurn.toLocaleString()}/mo</div>
                </div>
                <div>
                  <div className="text-xs text-muted-foreground">Liquidity Runway</div>
                  <div className="text-lg font-bold">{state.stressResult.liquidityRunway} months</div>
                </div>
                <div>
                  <div className="text-xs text-muted-foreground">Risk Score Change</div>
                  <div className="text-lg font-bold text-red-600">
                    {state.stressResult.riskScoreBefore} → {state.stressResult.riskScoreAfter}
                    <span className="text-sm ml-1">(+{state.stressResult.riskScoreDelta})</span>
                  </div>
                </div>
                <div>
                  <div className="text-xs text-muted-foreground">Portfolio Under Stress</div>
                  <div className="text-lg font-bold">${state.stressResult.portfolioStressValue.toLocaleString()}</div>
                </div>
              </div>
            </CardContent>
          </Card>
          <DepletionChart timeline={state.stressResult.depletionTimeline} />
        </div>
      )}
    </div>
  );
}
